create table if not exists runtime_regions (id uuid primary key default gen_random_uuid(), region_code text not null unique, status text not null, updated_at timestamptz not null);
create table if not exists regional_failovers (id uuid primary key default gen_random_uuid(), from_region text not null, to_region text not null, reason text not null, occurred_at timestamptz not null);
create table if not exists regional_queue_routes (id uuid primary key default gen_random_uuid(), tenant_id text not null, region_code text not null, queue_name text not null, updated_at timestamptz not null);
create table if not exists region_feature_flags (id uuid primary key default gen_random_uuid(), region_code text not null, flag_key text not null, enabled boolean not null, updated_at timestamptz not null);
create table if not exists sovereign_policies (id uuid primary key default gen_random_uuid(), country text not null unique, policy jsonb not null, updated_at timestamptz not null);
create table if not exists data_residency_rules (id uuid primary key default gen_random_uuid(), country text not null, dataset text not null, residency_region text not null, updated_at timestamptz not null, unique(country, dataset));
create table if not exists cross_region_replication_logs (id uuid primary key default gen_random_uuid(), source_region text not null, target_region text not null, status text not null, created_at timestamptz not null);
create table if not exists sovereign_audit_exports (id uuid primary key default gen_random_uuid(), country text not null, export_type text not null, created_at timestamptz not null);
create table if not exists jurisdiction_rules (id uuid primary key default gen_random_uuid(), jurisdiction text not null, rule_key text not null, rule_value jsonb not null, updated_at timestamptz not null, unique(jurisdiction, rule_key));
create table if not exists consent_records (id uuid primary key default gen_random_uuid(), tenant_id text not null, subject_id text not null, consent_type text not null, granted boolean not null, created_at timestamptz not null);
create table if not exists regional_compliance_reports (id uuid primary key default gen_random_uuid(), jurisdiction text not null, report_type text not null, payload jsonb not null, created_at timestamptz not null);
create table if not exists ai_compliance_policies (id uuid primary key default gen_random_uuid(), jurisdiction text not null, provider text not null, max_tokens int not null, updated_at timestamptz not null, unique(jurisdiction, provider));
create table if not exists provider_routes (id uuid primary key default gen_random_uuid(), provider_type text not null, country text not null, region text not null, updated_at timestamptz not null, unique(provider_type, country));
create table if not exists geo_execution_logs (id uuid primary key default gen_random_uuid(), route_key text not null, region text not null, latency_ms int not null, created_at timestamptz not null);
create table if not exists regional_provider_health (id uuid primary key default gen_random_uuid(), provider text not null, region text not null, status text not null, updated_at timestamptz not null, unique(provider, region));
create table if not exists latency_profiles (id uuid primary key default gen_random_uuid(), region text not null, latency_ms int not null, created_at timestamptz not null);
